import { describe, expect, it } from "vitest";

import * as Schema from "./schema.js";
import { Worker } from "./worker.js";

describe("Worker", () => {
	it("includes sdkVersion, databases, and capabilities in manifest", () => {
		const worker = new Worker();
		const tasks = worker.database("tasks", {
			type: "managed",
			initialTitle: "Tasks",
			primaryKeyProperty: "Name",
			schema: {
				properties: {
					Name: Schema.title(),
				},
			},
		});

		worker.sync("tasksSync", {
			database: tasks,
			execute: async () => ({
				changes: [],
				hasMore: false,
			}),
		});

		expect(worker.manifest.sdkVersion).toMatch(/^\d+\.\d+\.\d+/);
		expect(worker.manifest.databases).toEqual([
			{
				key: "tasks",
				config: {
					type: "managed",
					initialTitle: "Tasks",
					primaryKeyProperty: "Name",
					schema: {
						properties: {
							Name: { type: "title" },
						},
					},
				},
			},
		]);
		expect(worker.manifest.pacers).toEqual([]);
		expect(worker.manifest.capabilities).toEqual([
			{
				_tag: "sync",
				key: "tasksSync",
				config: {
					databaseKey: "tasks",
					primaryKeyProperty: "Name",
					mode: undefined,
					schedule: undefined,
				},
			},
		]);
	});

	it("serializes manual schedules in the manifest", () => {
		const worker = new Worker();
		const tasks = worker.database("tasks", {
			type: "managed",
			initialTitle: "Tasks",
			primaryKeyProperty: "Name",
			schema: {
				properties: {
					Name: Schema.title(),
				},
			},
		});

		worker.sync("tasksBackfill", {
			database: tasks,
			schedule: "manual",
			execute: async () => ({
				changes: [],
				hasMore: false,
			}),
		});

		expect(worker.manifest.capabilities).toEqual([
			{
				_tag: "sync",
				key: "tasksBackfill",
				config: {
					databaseKey: "tasks",
					primaryKeyProperty: "Name",
					mode: undefined,
					schedule: {
						type: "manual",
					},
				},
			},
		]);
	});

	it("includes pacers in manifest and links to sync capabilities", () => {
		const worker = new Worker();
		const tasks = worker.database("tasks", {
			type: "managed",
			initialTitle: "Tasks",
			primaryKeyProperty: "Name",
			schema: {
				properties: {
					Name: Schema.title(),
				},
			},
		});

		const _jiraPacer = worker.pacer("jira", {
			allowedRequests: 10,
			intervalMs: 1000,
		});

		worker.sync("jiraBackfill", {
			database: tasks,
			schedule: "manual",
			execute: async () => ({
				changes: [],
				hasMore: false,
			}),
		});

		worker.sync("jiraDelta", {
			database: tasks,
			schedule: "5m",
			execute: async () => ({
				changes: [],
				hasMore: false,
			}),
		});

		expect(worker.manifest.pacers).toEqual([
			{
				key: "jira",
				config: {
					allowedRequests: 10,
					intervalMs: 1000,
				},
			},
		]);
	});

	it("rejects duplicate keys across databases, pacers, and capabilities", () => {
		const worker = new Worker();
		const db = worker.database("shared-key", {
			type: "managed",
			initialTitle: "Tasks",
			primaryKeyProperty: "Name",
			schema: {
				properties: {
					Name: Schema.title(),
				},
			},
		});

		expect(() =>
			worker.sync("shared-key", {
				database: db,
				execute: async () => ({
					changes: [],
					hasMore: false,
				}),
			}),
		).toThrow('Worker item with key "shared-key" already registered');
	});
});
